import e from"../index.min.js";import{hwid as t}from"./discover.min.js";export async function getOrCreateIdentity(n={}){let i=n.seed||null;if(i||(i=process.env.ZEN_IDENTITY_SEED||null),!i){const e=process.argv.indexOf("--identity-file");if(-1!==e&&process.argv[e+1])try{const{readFileSync:t}=await import("node:fs");i=t(process.argv[e+1],"utf8").trim()}catch(e){}}if(!i&&n.identityFile)try{const{readFileSync:e}=await import("node:fs");i=e(n.identityFile,"utf8").trim()}catch(e){}if(i){const t=await e.hash(i,null,null,{name:"SHA-256",encode:"base62"});return{pair:await e.pair(null,{seed:t}),seed:t,hwid:null,mode:"seed"}}const r=t();if(!r)return null;const a=await e.hash(r,null,null,{name:"SHA-256",encode:"base62"});return{pair:await e.pair(null,{seed:a}),seed:a,hwid:r,mode:"hardware"}}export async function getIdentity(){return getOrCreateIdentity()}